type escalationFloorFinder interface {
	Next(actualPower int) (int, error)
}

type tryLoopFloorFinder struct {
	ladder escalationFloorFinder
}

func (f tryLoopFloorFinder) Next(actualPower int) (int, error) {
	return nextEscalationFloor(f.ladder, actualPower)
}

func isBudgetExhaustedFailure(report agent.ExecuteBeadReport) bool {
	return strings.Contains(report.Detail, agent.RateLimitBudgetExhaustedReason)
}

func normalizeProviderConnectivityRetryReport(report *agent.ExecuteBeadReport) {
	if report == nil || report.Status != agent.ExecuteBeadStatusExecutionFailed {
		return
	}
	if !isProviderConnectivityAttemptReport(*report) {
		return
	}
	report.OutcomeReason = agent.FailureModeProviderConnectivity
	report.Disrupted = true
	report.DisruptionReason = "provider_connectivity"
}

func isProviderConnectivityAttemptReport(report agent.ExecuteBeadReport) bool {
	if strings.TrimSpace(report.Provider) == "" {
		return false
	}
	combined := strings.ToLower(strings.Join([]string{
		report.Detail,
		report.Error,
		report.Stderr,
	}, "\n"))
	for _, marker := range []string{"provider_connectivity", "connection refused", "connection reset", "no route to host", "network is unreachable", "i/o timeout", "dial tcp"} {
		if strings.Contains(combined, marker) {
			return true
		}
	}
	return false
}

func nextEscalationFloor(l escalationFloorFinder, actualPower int) (int, error) {
	if l == nil {
		return 0, powerladder.ErrLadderExhausted
	}
	floor := actualPower
	for {
		next, err := l.Next(floor)
		if err == nil {
			return next, nil
		}
		var nvp *powerladder.NoViableProviderError
		if errors.As(err, &nvp) {
			floor = nvp.Floor
			continue
		}
		return 0, err
	}
}

func highestViableEscalationFloor(l escalationFloorFinder) (int, error) {
	if l == nil {
		return 0, powerladder.ErrLadderExhausted
	}
	floor := 0
	highest := 0
	for {
		next, err := nextEscalationFloor(l, floor)
		if err != nil {
			if errors.Is(err, powerladder.ErrLadderExhausted) && highest > 0 {
				return highest, nil
			}
			return 0, err
		}
		if next <= floor {
			if highest > 0 {
				return highest, nil
			}
			return 0, powerladder.ErrLadderExhausted
		}
		highest = next
		floor = next
	}
}

func investigationRetryInitialMinPower(b *bead.Bead, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, agent.ExecuteBeadReport, bool) {
	return baseMinPower, agent.ExecuteBeadReport{}, false
}

func recentProviderConnectivityMinPower(store *bead.Store, now time.Time, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, agent.ExecuteBeadReport, bool) {
	if store == nil || ladder == nil {
		return baseMinPower, agent.ExecuteBeadReport{}, false
	}
	beads, err := store.List("", "", nil)
	if err != nil {
		return baseMinPower, agent.ExecuteBeadReport{}, false
	}
	floor := baseMinPower
	for _, b := range beads {
		events, err := store.Events(b.ID)
		if err != nil {
			continue
		}
		if next, ok := recentProviderConnectivityMinPowerFromEvents(events, now, floor, maxPower, ladder); ok {
			if next >= maxPower && maxPower > 0 {
				return baseMinPower, routeUnavailableReport(&b, next, maxPower, nil), true
			}
			if next > floor {
				floor = next
			}
		}
	}
	if floor > baseMinPower {
		return floor, agent.ExecuteBeadReport{}, true
	}
	return baseMinPower, agent.ExecuteBeadReport{}, false
}

func recentProviderConnectivityMinPowerFromEvents(events []bead.BeadEvent, now time.Time, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, bool) {
	if len(events) == 0 || ladder == nil {
		return baseMinPower, false
	}
	floor := baseMinPower
	var last recentRouteEvent
	for _, ev := range events {
		if ev.CreatedAt.IsZero() || now.Sub(ev.CreatedAt) > agent.ProviderUnavailableCooldown || ev.CreatedAt.After(now.Add(time.Minute)) {
			continue
		}
		if route, ok := routeEventFromBeadEvent(ev); ok {
			last = route
			continue
		}
		if ev.Kind == "route-failure" {
			route, ok := routeFailureEventFromBeadEvent(ev)
			if !ok {
				continue
			}
			if next, ok := nextFloorForRecentConnectivity(route.ActualPower, maxPower, ladder); ok && next > floor {
				floor = next
			}
			continue
		}
		if ev.Kind == "execute-bead" && strings.EqualFold(strings.TrimSpace(ev.Summary), "execution_failed") && isProviderConnectivityEventBody(ev.Body) && last.Provider != "" {
			if next, ok := nextFloorForRecentConnectivity(last.ActualPower, maxPower, ladder); ok && next > floor {
				floor = next
			}
		}
	}
	return floor, floor > baseMinPower
}

type recentRouteEvent struct {
	Provider    string
	Model       string
	ActualPower int
}

func routeEventFromBeadEvent(ev bead.BeadEvent) (recentRouteEvent, bool) {
	if ev.Kind != "routing" && ev.Kind != "execution-routing-intent" {
		return recentRouteEvent{}, false
	}
	var body map[string]any
	if err := json.Unmarshal([]byte(ev.Body), &body); err != nil {
		return recentRouteEvent{}, false
	}
	route := recentRouteEvent{
		Provider:    firstNonEmptyString(body["resolved_provider"], body["actual_provider"], body["provider"]),
		Model:       firstNonEmptyString(body["resolved_model"], body["actual_model"], body["model"]),
		ActualPower: intFromAny(body["actual_power"]),
	}
	if route.Provider == "" {
		return recentRouteEvent{}, false
	}
	return route, true
}

func routeFailureEventFromBeadEvent(ev bead.BeadEvent) (recentRouteEvent, bool) {
	var body map[string]any
	if err := json.Unmarshal([]byte(ev.Body), &body); err != nil {
		return recentRouteEvent{}, false
	}
	if reason := strings.TrimSpace(fmt.Sprint(body["outcome_reason"])); reason != "" && reason != agent.FailureModeProviderConnectivity {
		return recentRouteEvent{}, false
	}
	route := recentRouteEvent{
		Provider:    firstNonEmptyString(body["provider"]),
		Model:       firstNonEmptyString(body["model"]),
		ActualPower: intFromAny(body["actual_power"]),
	}
	if route.Provider == "" {
		return recentRouteEvent{}, false
	}
	return route, true
}

func nextFloorForRecentConnectivity(actualPower, maxPower int, ladder escalationFloorFinder) (int, bool) {
	next, err := nextEscalationFloor(ladder, actualPower)
	if err != nil {
		return 0, false
	}
	if maxPower > 0 && next >= maxPower {
		return next, true
	}
	return next, next > 0
}

func isProviderConnectivityEventBody(body string) bool {
	lower := strings.ToLower(body)
	for _, marker := range []string{"dial tcp", "i/o timeout", "connection refused", "connection reset", "no route to host", "provider error"} {
		if strings.Contains(lower, marker) {
			return true
		}
	}
	return false
}

func firstNonEmptyString(values ...any) string {
	for _, value := range values {
		if s := strings.TrimSpace(fmt.Sprint(value)); s != "" && s != "<nil>" {
			return s
		}
	}
	return ""
}

func intFromAny(value any) int {
	switch v := value.(type) {
	case int:
		return v
	case int64:
		return int(v)
	case float64:
		return int(v)
	case json.Number:
		i, _ := v.Int64()
		return int(i)
	default:
		return 0
	}

	}
}

// resolvePowerFloor maps an inferred power class to a concrete ladder floor.
// When the ladder cannot satisfy the requested class, it degrades through the
// hierarchy (Smart → Standard → Cheap) per ADR-024 P1 ("cheapest first") so
// dispatch hands the bead to Fizeau with a viable bound rather than failing
// outright. Returning (0, false) means "no MinPower pin; let Fizeau pick".
func resolvePowerFloor(powerClass policyescalation.PowerClass, ladder escalationFloorFinder) (int, bool) {
	switch powerClass {
	case policyescalation.PowerSmart:
		if floor, err := highestViableEscalationFloor(ladder); err == nil {
			return floor, true
		}
		return resolvePowerFloor(policyescalation.PowerStandard, ladder)
	case policyescalation.PowerStandard:
		first, err := nextEscalationFloor(ladder, 0)
		if err != nil {
			return 0, false
		}
		second, err := nextEscalationFloor(ladder, first)
		if err != nil {
			return first, true
		}
		return second, true
	default:
		return 0, false
	}
}

// zeroConfigInitialMinPower selects the initial MinPower for a bead when the
// caller has no explicit routing flags or project routing config. The third
// return value carries a degradation note when the inferred class could not
// be pinned to a ladder floor and was downgraded to Cheap-equivalent
// (no MinPower pin). Callers should propagate the note into RoutingIntentNote
// so the evidence stream records why dispatch ended up unpinned.
func zeroConfigInitialMinPower(b *bead.Bead, powerClass policyescalation.PowerClass, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, agent.ExecuteBeadReport, string, bool) {
	if powerClass == "" {
		return baseMinPower, agent.ExecuteBeadReport{}, "", false
	}
	powerFloor, hasPowerFloor := resolvePowerFloor(powerClass, ladder)
	if !hasPowerFloor {
		note := ""
		if powerClass != policyescalation.PowerCheap {
			note = fmt.Sprintf(
				"no ladder floor for inferred powerClass %s; degraded to cheap-equivalent (no MinPower pin)",
				powerClass,
			)
		}
		return baseMinPower, agent.ExecuteBeadReport{}, note, false
	}
	if powerFloor > baseMinPower {
		if maxPower > 0 && powerFloor >= maxPower {
			return baseMinPower, routeUnavailableReport(b, powerFloor, maxPower, nil), "", true
		}
		return powerFloor, agent.ExecuteBeadReport{}, "", false
	}
	return baseMinPower, agent.ExecuteBeadReport{}, "", false
}

func routeUnavailableReport(b *bead.Bead, minPower, maxPower int, cause error) agent.ExecuteBeadReport {
	beadID := ""
	if b != nil {
		beadID = b.ID
	}
	detail := fmt.Sprintf("route unavailable: no viable routing candidate satisfies requested MinPower %d", minPower)
	if maxPower > 0 {
		detail += fmt.Sprintf(" and MaxPower %d", maxPower)
	}
	if cause != nil {
		detail += ": " + cause.Error()
	}
	return agent.ExecuteBeadReport{
		BeadID:        beadID,
		Status:        agent.ExecuteBeadStatusExecutionFailed,
		Detail:        detail,
		OutcomeReason: agent.FailureModeNoViableProvider,
	}
}

func runEscalatingPowerAttempts(
	ctx context.Context,
	initialMinPower int,
	ladder escalationFloorFinder,
	attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
	recordAttempt func(agent.ExecuteBeadReport),
	perBeadTracker *policyescalation.PerBeadCostTracker,
	allowInfrastructureRetry bool,
) (agent.ExecuteBeadReport, error) {
	minPower := initialMinPower
	floors := tryLoopFloorFinder{ladder: ladder}
	for {
		report, err := attempt(ctx, minPower)
		if recordAttempt != nil && report.BeadID != "" {
			recordAttempt(report)
		}
		if perBeadTracker != nil {
			perBeadTracker.Add(report.Harness, report.CostUSD)
		}
		if err != nil {
			return report, err
		}
		if perBeadTracker != nil {
			if detail, tripped := perBeadTracker.Tripped(); tripped {
				report.Status = agent.ExecuteBeadStatusExecutionFailed
				report.Detail = detail
				report.CostUSD = perBeadTracker.Spent()
				return report, nil
			}
		}
		normalizeProviderConnectivityRetryReport(&report)
		transition := executeloop.DecideAttemptTransition(executeloop.AttemptTransitionInput{
			Status:                   report.Status,
			Detail:                   report.Detail,
			CurrentMinPower:          minPower,
			ActualPower:              report.ActualPower,
			OutcomeReason:            report.OutcomeReason,
			Disrupted:                report.Disrupted,
			BudgetExhausted:          isBudgetExhaustedFailure(report),
			AllowInfrastructureRetry: allowInfrastructureRetry,
		}, floors)
		if transition.Action != executeloop.TryLoopActionRetryPower {
			return report, nil
		}
		minPower = transition.NextMinPower
	}
}

// BeadCancelStore reads/writes the cancel markers on a bead's Extra map.
// Implemented by *bead.Store. ADR-022 §Cancel SLA: the worker polls
// IsCancelRequested mid-attempt and on a positive read writes
// MarkCancelHonored before aborting at the next safe point.
type BeadCancelStore interface {
	IsCancelRequested(id string) (bool, error)
	MarkCancelHonored(id string) error
}

// CancelPollInterval is how often the worker checks for an operator cancel
// while an agent attempt is in flight. ADR-022 §Cancel SLA names 10s as the
// default. Exposed as a variable so tests can override it.
var CancelPollInterval = 10 * time.Second

// RunStateRefreshInterval controls how often execute-bead refreshes its
// per-attempt liveness record while the agent harness is running. Exposed as a
// variable so tests can shorten it without slowing production attempts.
var RunStateRefreshInterval = 10 * time.Second

// ExecuteBeadRuntime carries the non-durable plumbing for an execute-bead
// run: per-invocation intent (FromRev, PromptFile, WorkerID) and
// non-serializable injection seams (BeadEvents, Service, AgentRunner).
// Durable knobs (Harness, Model, Provider, Effort,
// ContextBudget, MirrorCfg) live on config.ResolvedConfig and are passed
// via ExecuteBeadWithConfig's rcfg argument.
//
// See SD-024 / TD-024 §Runtime structs and §Stage 3.
type ExecuteBeadRuntime struct {
	FromRev         string // base git revision (default: HEAD)
	PromptFile      string // override prompt file (auto-generated if empty)
	Output          io.Writer
	WorkerID        string // from DDX_WORKER_ID env or caller
	BeadEvents      BeadEventAppender
	BeadCancel      BeadCancelStore // optional: enables operator-cancel mid-attempt poll
	ResourceChecker ExecutionResourceChecker
	Service         agentlib.FizeauService
	AgentRunner     AgentRunner
	AttemptBackend  AttemptBackend
	// RateLimitMaxWait bounds the per-bead total wait spent on rate-limit
	// retries (ddx-c6e3db02 RateLimitRetryContract / TD-031 §8.4). Zero uses
	// RateLimitRetryDefaultBudget (5 min). Negative disables the wrapper —
	// rate-limit responses fall through to the standard execution_failed path.
	RateLimitMaxWait time.Duration
	// PreserveAttemptWorktree keeps the attempt worktree on disk after the
	// attempt finishes. It is used by inspection-oriented runs such as
	// `ddx try --no-merge`.
	PreserveAttemptWorktree bool
	// ACCheckRunner, when non-nil, runs ddx bead ac-check for the given bead
	// and attempt after the agent commits, writing ac-check.json to the
	// attempt dir under wtPath. When nil, ac-check is skipped.
	ACCheckRunner func(ctx context.Context, beadID, attemptID, wtPath string) (*accheck.Output, error)
}

type onRouteResolvedKeyType struct{}

// contextWithOnRouteResolved stores fn in ctx so execute-bead can retrieve it
// after the Executor dispatches through agenttry.Attempt.
func contextWithOnRouteResolved(ctx context.Context, fn func(harness, provider, model string)) context.Context {
	return context.WithValue(ctx, onRouteResolvedKeyType{}, fn)
}

// onRouteResolvedFromContext retrieves the callback stored by
// contextWithOnRouteResolved, or nil if none was stored.
func onRouteResolvedFromContext(ctx context.Context) func(harness, provider, model string) {
	fn, _ := ctx.Value(onRouteResolvedKeyType{}).(func(harness, provider, model string))
	return fn
}

// GitOps abstracts the git operations required by the worker.
// Merge is intentionally excluded — that belongs to the parent-side
// orchestrator (OrchestratorGitOps). UpdateRef/DeleteRef are exposed here
// so landing-side helpers (e.g. BuildLandingGateContext) can pin a
// transient ref while running gate evaluation against an ephemeral
// worktree.
type GitOps interface {
	HeadRev(dir string) (string, error)
	ResolveRev(dir, rev string) (string, error)
	WorktreeAdd(dir, wtPath, rev string) error
	WorktreeRemove(dir, wtPath string) error
	WorktreeList(dir string) ([]string, error)
	WorktreePrune(dir string) error
	IsDirty(dir string) (bool, error)
	// SynthesizeCommit stages real file changes (excluding harness noise paths) and
	// commits them using msg as the commit message. Returns (true, nil) when a
	// commit was made, (false, nil) when there was nothing real to commit (all
	// dirty files were noise), and (false, err) on failure.
	SynthesizeCommit(dir, msg string) (bool, error)
	// UpdateRef updates ref in dir to sha. Used by landing helpers to pin a
	// commit so a transient worktree can check it out without racing with
	// other work that might prune it.
	UpdateRef(dir, ref, sha string) error
	// DeleteRef removes ref from dir. Used to unpin a transient ref after
	// the consumer (e.g. an ephemeral worktree) is done with it.
	DeleteRef(dir, ref string) error
}

// AgentRunner runs an agent with the given options.
type AgentRunner interface {
	Run(opts RunArgs) (*Result, error)
}

type staticCandidateResultPass struct {
	candidate CandidateResult
}

func (p staticCandidateResultPass) Execute(context.Context, string) (CandidateResult, error) {
	return p.candidate, nil
}

func applyWorkerCandidateCycle(ctx context.Context, projectRoot, wtPath string, runtime ExecuteBeadRuntime, res *ExecuteBeadResult) error {
	if res == nil || wtPath == "" || res.Status != ExecuteBeadStatusSuccess {
		return nil
	}

	_ = MarkWorktreeActiveCycle(wtPath)
	defer func() {
		_ = ClearWorktreeActiveCycle(wtPath)
	}()

	coord := &AttemptCycleCoordinator{
		Pass: staticCandidateResultPass{
			candidate: CandidateResult{
				Report:       ReportFromExecuteBeadResult(res, ""),
				WorktreePath: wtPath,
				CycleIndex:   res.CycleIndex,
			},
		},
		RefStore:    &GitCandidateRefStore{},
		ProjectRoot: projectRoot,
		BeadEvents:  runtime.BeadEvents,
	}
	cycleResult, err := coord.Run(ctx, res.BeadID)
	if err != nil {
		return err
	}
	res.CandidateRef = cycleResult.Report.CandidateRef
	res.CycleIndex = cycleResult.Report.CycleIndex
	res.CycleTrace = append([]ExecutionCycleTrace(nil), cycleResult.Report.CycleTrace...)
	return nil
}

